import litellm
from tenacity import retry, stop_after_attempt, wait_exponential

@retry(stop=stop_after_attempt(3), wait=wait_exponential(multiplier=1, min=1, max=10))
def resilient_call(messages: list[dict], prefer_open: bool = False) -> str:
    """Call preferred backend with automatic retry and closed-model fallback."""
    try:
        if prefer_open:
            resp = litellm.completion(
                model="openai/meta-llama/Llama-3.1-70B-Instruct",
                messages=messages,
                api_base="http://inference.internal:8000/v1",
                api_key="none",
                timeout=30,
            )
            return resp.choices[0].message.content
    except Exception:
        pass  # fall through to closed-model fallback

    resp = litellm.completion(
        model="claude-3-5-haiku-20241022",
        messages=messages,
        timeout=30,
    )
    return resp.choices[0].message.content
